#include <stdio.h>
#include <math.h>

int main(void) {
    double celsius;

    scanf("%lf", &celsius);

    if (celsius < -50.0 || celsius > 50.0) {
        printf("Error: temperature out of range\n");
    } else {
        double fahrenheit = (celsius * 9.0 / 5.0) + 32.0;
        printf("%.1f\n", fahrenheit);
    }

    return 0;
}
